cat > /tmp/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = new List<(string project, string code, string file, int line, string message)>();
var warnings = new List<(string project, string code, string file, int line, string message)>();

void Visit(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name ?? currentProject;
    if (node is Target t && t.Project is Project tp)
        currentProject = tp.Name ?? currentProject;

    if (node is Error e)
    {
        errors.Add((currentProject, e.Code ?? "", e.File ?? "", e.LineNumber, e.Text ?? e.ToString()));
    }
    if (node is Warning w)
    {
        warnings.Add((currentProject, w.Code ?? "", w.File ?? "", w.LineNumber, w.Text ?? w.ToString()));
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                Visit(bn, currentProject);
        }
    }
}

Visit(build);

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var (proj, code, file, line, msg) in errors)
{
    Console.WriteLine($"[{proj}] {code}: {file}({line}): {msg}");
    Console.WriteLine();
}

Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var (proj, code, file, line, msg) in warnings)
{
    Console.WriteLine($"[{proj}] {code}: {file}({line}): {msg}");
    Console.WriteLine();
}

// Show project dependency info
Console.WriteLine("=== PROJECT STRUCTURE ===");
void VisitProjects(BaseNode node, int depth = 0)
{
    if (node is Project p)
    {
        var succeeded = p.Children.OfType<Target>().All(t => t.Succeeded);
        Console.WriteLine($"{new string(' ', depth*2)}- {p.Name} (Succeeded: {succeeded})");
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                VisitProjects(bn, node is Project ? depth + 1 : depth);
        }
    }
}
VisitProjects(build);
