cat > /tmp/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Deep dive: find source file contents and project references from the binlog
Console.WriteLine("=== DETAILED PROJECT ANALYSIS ===");

void VisitAll(BaseNode node, string context = "", int depth = 0)
{
    var prefix = new string(' ', depth * 2);

    if (node is Project p)
    {
        context = p.Name ?? "";
        // Look for project references, package references
        Console.WriteLine($"\n{prefix}PROJECT: {p.Name} | ProjectFile: {p.ProjectFile}");
    }

    if (node is Target t)
    {
        if (t.Name == "ResolvePackageAssets" || t.Name == "ResolveAssemblyReferences" || 
            t.Name == "ResolveProjectReferences" || t.Name == "Restore" || t.Name == "Csc" ||
            t.Name == "_GetRestoreProjectStyle" || t.Name == "CollectPackageReferences")
        {
            Console.WriteLine($"{prefix}TARGET: {t.Name} (Succeeded: {t.Succeeded}) in {context}");
        }
    }

    if (node is Item item)
    {
        if (item.Name?.Contains("PackageReference") == true || item.Name?.Contains("ProjectReference") == true)
        {
            Console.WriteLine($"{prefix}ITEM: {item.Name} = {item.Text}");
        }
    }

    if (node is AddItem ai)
    {
        if (ai.Name?.Contains("PackageReference") == true || ai.Name?.Contains("ProjectReference") == true)
        {
            Console.WriteLine($"{prefix}ADD_ITEM: {ai.Name}");
            foreach (var child in ai.Children)
            {
                if (child is Item ci)
                    Console.WriteLine($"{prefix}  -> {ci.Text}");
            }
        }
    }

    if (node is NamedNode nn && nn.Name?.Contains("PackageReference") == true)
    {
        Console.WriteLine($"{prefix}NAMED: {nn.GetType().Name} {nn.Name} = {nn}");
    }

    if (node is Message m && (m.Text?.Contains("PackageReference") == true || m.Text?.Contains("Newtonsoft") == true))
    {
        Console.WriteLine($"{prefix}MSG [{context}]: {m.Text}");
    }

    if (node is Error e)
    {
        Console.WriteLine($"{prefix}ERROR [{context}]: {e.Code} in {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Text}");
    }

    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                VisitAll(bn, context, depth + 1);
        }
    }
}

VisitAll(build);

// Also show evaluated properties related to packages
Console.WriteLine("\n=== LOOKING FOR PACKAGE-RELATED PROPERTIES ===");
void FindProps(BaseNode node, string ctx = "")
{
    if (node is Project p) ctx = p.Name ?? ctx;
    if (node is Property prop && (prop.Name?.Contains("Package") == true || prop.Name?.Contains("Newtonsoft") == true))
    {
        Console.WriteLine($"  [{ctx}] {prop.Name} = {prop.Value}");
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
            if (child is BaseNode bn) FindProps(bn, ctx);
    }
}
FindProps(build);
