cat > /tmp/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Extract PackageReference items per project
Console.WriteLine("=== PACKAGE REFERENCES PER PROJECT ===");
void FindPackageRefs(BaseNode node, string ctx = "")
{
    if (node is Project p) ctx = p.Name ?? ctx;

    if (node is AddItem ai && ai.Name == "PackageReference")
    {
        foreach (var child in ai.Children)
        {
            if (child is Item ci)
            {
                // Get metadata
                var metadata = "";
                foreach (var mc in ci.Children)
                {
                    if (mc is Metadata md)
                        metadata += $" {md.Name}={md.Value}";
                }
