Console.WriteLine("=== FULL TREE DUMP FOR Services.csproj (build pass with errors) ===");
int svcIdx = 0;
void DumpTree(BaseNode node, string ctx = "", int depth = 0)
{
    if (node is Project p)
    {
        ctx = p.Name ?? ctx;
        if (ctx != "Services.csproj") 
        {
            if (node is TreeNode tn2)
                foreach (var child in tn2.Children)
                    if (child is BaseNode bn) DumpTree(bn, ctx, depth);
            return;
        }
        svcIdx++;
        // Only dump the instance that has errors (the build pass)
        bool hasErrors = false;
        void CheckErrors(BaseNode n)
        {
            if (n is Error) hasErrors = true;
            if (n is TreeNode t) foreach (var c in t.Children) if (c is BaseNode b) CheckErrors(b);
        }
        CheckErrors(p);
        if (!hasErrors)
        {
            if (node is TreeNode tn3)
                foreach (var child in tn3.Children)
                    if (child is BaseNode bn) DumpTree(bn, ctx, depth);
            return;
        }
        Console.WriteLine($"\nServices.csproj instance #{svcIdx} (HAS ERRORS):");
    }

    if (ctx != "Services.csproj") return;

    var prefix = new string(' ', depth * 2);
    var nodeType = node.GetType().Name;
    var display = node switch
    {
        Target t => $"Target: {t.Name} (Succeeded: {t.Succeeded})",
        MSTask t => $"Task: {t.Name}",
        AddItem ai => $"AddItem: {ai.Name} ({ai.Children.Count} items)",
        Item i => $"Item: {i.Text}",
        Metadata m => $"Metadata: {m.Name}={m.Value}",
        Property prop => $"Property: {prop.Name}={prop.Value?.Substring(0, Math.Min(100, prop.Value?.Length ?? 0))}",
        Parameter param => $"Parameter: {param.Name} ({param.Children.Count} children)",
        Folder f => $"Folder: {f.Name}",
        Message m => $"Message: {m.Text?.Substring(0, Math.Min(120, m.Text?.Length ?? 0))}",
        Error e => $"ERROR: {e.Code}: {e.Text}",
        _ => $"{nodeType}: {node}"
    };

    if (depth <= 4 || node is Error || node is AddItem || node is Item && depth <= 6)
        Console.WriteLine($"{prefix}[{nodeType}] {display}");

    if (node is TreeNode tn)
        foreach (var child in tn.Children)
            if (child is BaseNode bn) DumpTree(bn, ctx, depth + 1);
}
DumpTree(build);
