using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;
using MSTask = Microsoft.Build.Logging.StructuredLogger.Task;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Find every project and dump its evaluated items
Console.WriteLine("=== PACKAGE & PROJECT REFERENCES ===");

void WalkForRefs(BaseNode node, string ctx = "", int depth = 0)
{
    if (node is Project p)
    {
        ctx = p.Name ?? ctx;
        // Check if this instance has errors
        bool hasErrors = false;
        void Check(BaseNode n) { if (n is Error) hasErrors = true; if (n is TreeNode t) foreach (var c in t.Children) if (c is BaseNode b) Check(b); }
        Check(p);

        bool hasCsc = false;
        void CheckCsc(BaseNode n) { if (n is MSTask t && t.Name == "Csc") hasCsc = true; if (n is TreeNode tn) foreach (var c in tn.Children) if (c is BaseNode b) CheckCsc(b); }
        CheckCsc(p);

        if (hasCsc)
            Console.WriteLine($"\n[{ctx}] (hasCsc={hasCsc}, hasErrors={hasErrors})");
        else
        {
            // still walk children for nested projects
            if (node is TreeNode tn2) foreach (var child in tn2.Children) if (child is BaseNode bn) WalkForRefs(bn, ctx, depth);
            return;
        }
    }

    // Look for AddItem nodes with PackageReference
    if (node is AddItem ai && (ai.Name == "PackageReference" || ai.Name == "ProjectReference" || ai.Name == "Reference"))
    {
        foreach (var child in ai.Children)
        {
            if (child is Item item)
            {
                var meta = string.Join(", ", item.Children.OfType<Metadata>().Select(m => $"{m.Name}={m.Value}"));
                Console.WriteLine($"  {ai.Name}: {item.Text} [{meta}]");
            }
        }
    }

    if (node is TreeNode tn)
        foreach (var child in tn.Children)
            if (child is BaseNode bn) WalkForRefs(bn, ctx, depth + 1);
}
WalkForRefs(build);

// Show the CSC command lines
Console.WriteLine("\n\n=== CSC COMMAND LINES ===");
void FindCscCmd(BaseNode node, string ctx = "")
