{
    Console.WriteLine("Found source files archive!");
    foreach (var entry in archives)
    {
        Console.WriteLine($"\n--- FILE: {entry.Key} ---");
        Console.WriteLine(entry.Value);
    }
}
else
{
    Console.WriteLine("No embedded source files found.");
}

