void FindFiles(BaseNode node, int depth = 0)
{
    if (node is SourceFile sf)
    {
        Console.WriteLine($"SourceFile: {sf.Name}");
        Console.WriteLine(sf.Text);
    }
    if (node is SourceFilesArchive sfa)
    {
        Console.WriteLine("Found SourceFilesArchive node");
    }
    if (node is TreeNode tn)
        foreach (var child in tn.Children)
            if (child is BaseNode bn) FindFiles(bn, depth + 1);
}
FindFiles(build);
