using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.IO;
using System.IO.Compression;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// The SourceFilesArchive is a byte[] that's a zip archive
var archive = build.SourceFilesArchive;
if (archive != null && archive.Length > 0)
{
    Console.WriteLine($"Source files archive: {archive.Length} bytes");
    using var ms = new MemoryStream(archive);
    using var zip = new ZipArchive(ms, ZipArchiveMode.Read);
    foreach (var entry in zip.Entries)
    {
        Console.WriteLine($"\n=== FILE: {entry.FullName} ===");
        using var reader = new StreamReader(entry.Open());
        Console.WriteLine(reader.ReadToEnd());
    }
}
else
{
    Console.WriteLine("No source files archive found.");

    // Try alternative: look at SourceFile nodes
    void FindSrc(BaseNode node)
    {
        if (node is SourceFile sf)
        {
            Console.WriteLine($"SourceFile node: {sf.Name} ({sf.SourceFilePath})");
        }
        if (node is TreeNode tn)
            foreach (var child in tn.Children)
                if (child is BaseNode bn) FindSrc(bn);
    }
    FindSrc(build);
}
