# The .cs files aren't embedded. Let's check the error details more carefully from the first analysis
# We already know the errors. Let's also check Api project's build - did it fail due to cascading?

cat > /tmp/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using MSTask = Microsoft.Build.Logging.StructuredLogger.Task;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check if Api.csproj had its own compile errors or just failed due to dependency
Console.WriteLine("=== ALL ERRORS AND FAILED TARGETS ===");
void FindFailures(BaseNode node, string ctx = "", int depth = 0)
{
    if (node is Project p)
    {
        ctx = p.Name ?? ctx;
    }

    if (node is Error e)
    {
        Console.WriteLine($"ERROR in [{ctx}]: {e.Code} - {e.File}({e.LineNumber}): {e.Text}");
    }

    if (node is Target t && !t.Succeeded && ctx != "BuildDiag.sln")
    {
        // Check if this target produced the errors
        bool hasOwnErrors = false;
        void CheckOwn(BaseNode n) { if (n is Error) hasOwnErrors = true; if (n is TreeNode tn2) foreach (var c in tn2.Children) if (c is BaseNode b) CheckOwn(b); }
        CheckOwn(t);

        if (t.Name == "Build" || t.Name == "Compile" || t.Name == "Csc" || t.Name == "CoreCompile" || 
            t.Name == "ResolveProjectReferences" || hasOwnErrors)
        {
            Console.WriteLine($"FAILED TARGET [{ctx}]: {t.Name} (hasOwnErrors: {hasOwnErrors})");
        }
    }

    if (node is TreeNode tn)
        foreach (var child in tn.Children)
            if (child is BaseNode bn) FindFailures(bn, ctx, depth + 1);
}
FindFailures(build);

// Check the dependency chain
Console.WriteLine("\n=== PROJECT DEPENDENCY CHAIN ===");
Console.WriteLine("Solution: BuildDiag.sln");
Console.WriteLine("  Core.csproj (no project refs, no package refs)");
Console.WriteLine("  Services.csproj -> Core.csproj");
Console.WriteLine("  Api.csproj -> Services.csproj, Core.csproj");
Console.WriteLine();
Console.WriteLine("From the csproj files:");
Console.WriteLine("  Services.csproj uses Newtonsoft.Json in code but has NO PackageReference for it");
CSHARP

cd /tmp/binlog-reader && dotnet run -- /tmp/sv-ef4a0f10473749f791efaea2a590aec7/build.binlog 2>&1 | grep -v "warning NU1603"

